// src/components/Quiz.js
import React, { useState } from "react";

export default function Quiz({ items, extractedText }) {
  const [selected, setSelected] = useState({});
  const [submitted, setSubmitted] = useState(false);

  if (!items || items.length === 0)
    return <p>No quiz generated.</p>;

  const generateMCQ = (answer) => {
    if (!answer || answer.trim() === "") return [];

    const wrongOptions = [
      answer + " नहीं",
      answer.slice(0, 2),
      answer + " संबंधित"
    ];

    const options = [answer, ...wrongOptions].sort(() => Math.random() - 0.5);

    return options;
  };

  const checkAnswer = (index) => {
    const chosen = selected[index];
    const correct = items[index].answer;
    return chosen === correct;
  };

  const onSubmit = () => setSubmitted(true);

  return (
    <div style={{
      padding: "20px",
      background: "#eff6ff",
      borderRadius: "10px",
      border: "1px solid #bfdbfe"
    }}>
      <h2 style={{ color: "#1e40af" }}>Quiz</h2>

      {items.map((q, i) => {
        const options = generateMCQ(q.answer);

        return (
          <div key={i} style={{
            marginBottom: "18px",
            background: "white",
            padding: "15px",
            borderRadius: "10px",
            border: "1px solid #dbeafe"
          }}>
            <strong>Q{i + 1}:</strong> {q.question}

            {options.map((op, idx) => (
              <label
                key={idx}
                style={{
                  display: "block",
                  marginTop: "8px",
                  cursor: "pointer"
                }}
              >
                <input
                  type="radio"
                  name={`q${i}`}
                  value={op}
                  onChange={() => setSelected({ ...selected, [i]: op })}
                  style={{ marginRight: "8px" }}
                />
                {op}
              </label>
            ))}

            {submitted && (
              <p style={{
                marginTop: "10px",
                color: checkAnswer(i) ? "green" : "red",
                fontWeight: "600"
              }}>
                {checkAnswer(i) ? "Correct" : `Wrong — Correct Answer: ${q.answer}`}
              </p>
            )}
          </div>
        );
      })}

      <button
        onClick={onSubmit}
        style={{
          background: "#1e40af",
          color: "white",
          padding: "10px 30px",
          borderRadius: "10px",
          border: "none",
          cursor: "pointer",
          marginTop: "15px",
          fontSize: "17px"
        }}
      >
        Submit Quiz
      </button>
    </div>
  );
}
